import React from "react";
import "./Top.css";

export default function Top() {
  function TopEvent() {
    document.body.scrollTop = 0; // For Safari
    document.documentElement.scrollTop = 0; // For Chrome, Firefox, IE and Opera
  }

  // When the user scrolls down 20px from the top of the document, show the button
  function scrollFunction() {
    const topButtonElement = document.getElementById("topButton") as HTMLElement | null;
    if (!topButtonElement) return;
    if (document.body.scrollTop > 20 || document.documentElement.scrollTop > 20) {
      topButtonElement.style.visibility = "visible";
    } else {
      topButtonElement.style.visibility = "hidden";
    }
  }

  React.useEffect(() => {
    const onScroll = () => scrollFunction();
    window.addEventListener("scroll", onScroll);
    // initial check
    scrollFunction();
    return () => {
      window.removeEventListener("scroll", onScroll);
    };
  }, []);

  // When the user clicks on the button, scroll to the top of the document
  return (
    <button onClick={TopEvent} id="topButton" title="Go to top">
      <i className="fas fa-hand-point-up" aria-hidden="true"></i>
    </button>
  );
}
